// src/components/Navbar.jsx
import React, { useState, useEffect, useRef } from "react";
import { motion, AnimatePresence, useMotionValue, useTransform } from "framer-motion";
import logo from "../assets/indiaadvertising-logo.png";
import { Menu, X, ChevronDown, Sparkles } from "lucide-react";
import localData from "../data/companyData.json";

const Navbar = () => {
  const [isOpen, setIsOpen] = useState(false);
  const [activeSection, setActiveSection] = useState("home");
  const [showProductsMenu, setShowProductsMenu] = useState(false);
  const constraintsRef = useRef(null);

  // Extract categories from your actual JSON data
  const categories = localData?.categories?.map(cat => cat.category) || [];

  const navItems = [
    { name: "Home", id: "home" },
    { name: "About", id: "about" },
    { name: "Products", id: "products", hasDropdown: true },
    { name: "Gallery", id: "gallery" },
    { name: "Contact", id: "contact" },
  ];

  const scrollToSection = (id) => {
    setIsOpen(false);
    setShowProductsMenu(false);
    setTimeout(() => {
      document.getElementById(id)?.scrollIntoView({ behavior: "smooth" });
    }, 100);
  };

  // Scroll Spy
  useEffect(() => {
    const handleScroll = () => {
      const scrollPosition = window.scrollY + 150;
      navItems.forEach((item) => {
        const section = document.getElementById(item.id);
        if (section) {
          const { offsetTop, offsetHeight } = section;
          if (scrollPosition >= offsetTop && scrollPosition < offsetTop + offsetHeight) {
            setActiveSection(item.id);
          }
        }
      });
    };
    window.addEventListener("scroll", handleScroll);
    handleScroll();
    return () => window.removeEventListener("scroll", handleScroll);
  }, []);

  // Magnetic effect for desktop nav items
  const MagneticItem = ({ children, onClick }) => {
    const ref = useRef(null);
    const x = useMotionValue(0);
    const y = useMotionValue(0);
    const scale = useTransform([x, y], ([x, y]) => 1 + Math.min(Math.sqrt(x * x + y * y) / 300, 0.1));

    const handleMouseMove = (e) => {
      const rect = ref.current.getBoundingClientRect();
      const centerX = rect.left + rect.width / 2;
      const centerY = rect.top + rect.height / 2;
      x.set(e.clientX - centerX);
      y.set(e.clientY - centerY);
    };

    const handleMouseLeave = () => {
      x.set(0);
      y.set(0);
    };

    return (
      <motion.div
        ref={ref}
        style={{ x, y, scale }}
        onMouseMove={handleMouseMove}
        onMouseLeave={handleMouseLeave}
        onClick={onClick}
        className="relative cursor-pointer"
        whileTap={{ scale: 0.95 }}
      >
        {children}
      </motion.div>
    );
  };

  return (
    <>
      <motion.nav
        initial={{ y: -100 }}
        animate={{ y: 0 }}
        className="fixed top-0 left-0 right-0 z-50"
        ref={constraintsRef}
      >
        {/* Floating Blob Background */}
        <motion.div
          className="absolute inset-0 pointer-events-none opacity-20"
          animate={{
            background: [
              "radial-gradient(circle at 20% 80%, #fbbf24, transparent 50%)",
              "radial-gradient(circle at 80% 20%, #3b82f6, transparent 50%)",
              "radial-gradient(circle at 40% 40%, #f59e0b, transparent 50%)",
            ],
          }}
          transition={{ duration: 20, repeat: Infinity, ease: "linear" }}
        />

        <div className="relative px-4 py-4 mx-auto max-w-7xl">
          <div className="flex items-center justify-between">
            {/* Logo */}
            <motion.div whileHover={{ scale: 1.1 }} whileTap={{ scale: 0.95 }}>
              <button onClick={() => scrollToSection("home")} className="flex items-center space-x-3">
                <div className="relative">
                  <img src={logo} alt="India Advertising" className="h-12 drop-shadow-lg" />
                  <motion.div
                    className="absolute rounded-full -inset-2 bg-yellow-400/30 blur-xl"
                    animate={{ scale: [1, 1.3, 1] }}
                    transition={{ duration: 4, repeat: Infinity }}
                  />
                </div>
                <span className="hidden text-2xl font-bold tracking-wider text-transparent bg-clip-text bg-gradient-to-r from-yellow-600 to-amber-400 sm:block">
                  INDIA ADVERTISING
                </span>
              </button>
            </motion.div>

            {/* Desktop Navigation */}
            <div className="items-center hidden space-x-8 md:flex">
              {navItems.map((item) => (
                <div key={item.name} className="relative">
                  <MagneticItem
                    onClick={() => {
                      if (item.hasDropdown) {
                        setShowProductsMenu(!showProductsMenu);
                      } else {
                        scrollToSection(item.id);
                      }
                    }}
                  >
                    <span
                      className={`relative text-lg font-medium transition-all duration-300 ${
                        activeSection === item.id
                          ? "text-yellow-600"
                          : "text-gray-800 hover:text-yellow-500"
                      }`}
                    >
                      {item.name}
                      {item.hasDropdown && (
                        <ChevronDown
                          size={18}
                          className={`inline-block ml-1 transition-transform ${
                            showProductsMenu ? "rotate-180" : ""
                          }`}
                        />
                      )}
                    </span>

                    {/* Glowing Active Indicator */}
                    {activeSection === item.id && (
                      <motion.div
                        layoutId="navbarActiveGlow"
                        className="absolute left-0 right-0 h-1 rounded-full shadow-lg -bottom-2 bg-gradient-to-r from-yellow-400 to-amber-600 shadow-yellow-500/50"
                        initial={{ width: 0 }}
                        animate={{ width: "100%" }}
                        transition={{ type: "spring", stiffness: 300 }}
                      />
                    )}
                  </MagneticItem>
                </div>
              ))}
            </div>

            {/* Mobile Menu Button */}
            <motion.button
              whileTap={{ scale: 0.9 }}
              onClick={() => setIsOpen(!isOpen)}
              className="p-3 rounded-full shadow-lg md:hidden bg-white/80 backdrop-blur"
            >
              <AnimatePresence mode="wait">
                {isOpen ? <X size={28} /> : <Menu size={28} />}
              </AnimatePresence>
            </motion.button>
          </div>
        </div>

        {/* PRODUCTS MEGA DROPDOWN */}
        <AnimatePresence>
          {showProductsMenu && (
            <motion.div
              initial={{ opacity: 0, y: -20 }}
              animate={{ opacity: 1, y: 0 }}
              exit={{ opacity: 0, y: -20 }}
              className="absolute left-0 right-0 mt-2 overflow-hidden border-t-4 border-yellow-500 shadow-2xl top-full bg-white/95 backdrop-blur-2xl"
            >
              <div className="px-8 py-10 mx-auto max-w-7xl">
                <div className="flex items-center mb-6">
                  <Sparkles className="mr-3 text-yellow-500" size={28} />
                  <h3 className="text-2xl font-bold text-gray-800">Explore Our Products</h3>
                </div>
                <div className="grid grid-cols-2 gap-6 md:grid-cols-4 lg:grid-cols-6">
                  {categories.length > 0 ? (
                    categories.map((cat, i) => (
                      <motion.div
                        key={cat}
                        initial={{ opacity: 0, y: 20 }}
                        animate={{ opacity: 1, y: 0 }}
                        transition={{ delay: i * 0.05 }}
                        onClick={() => {
                          scrollToSection("products");
                          setShowProductsMenu(false);
                        }}
                        className="p-5 text-center transition-all duration-300 border border-yellow-200 cursor-pointer rounded-2xl bg-gradient-to-br from-yellow-50 to-amber-50 hover:from-yellow-100 hover:to-amber-100 hover:shadow-xl hover:scale-105"
                      >
                        <div className="flex items-center justify-center w-16 h-16 mx-auto mb-3 rounded-full bg-yellow-200/50">
                          <span className="text-2xl">✦</span>
                        </div>
                        <p className="font-semibold text-gray-800">{cat}</p>
                      </motion.div>
                    ))
                  ) : (
                    <p className="py-8 text-center text-gray-500 col-span-full">
                      Loading categories...
                    </p>
                  )}
                </div>
              </div>
            </motion.div>
          )}
        </AnimatePresence>
      </motion.nav>

      {/* MOBILE FULLSCREEN MENU */}
      <AnimatePresence>
        {isOpen && (
          <motion.div
            initial={{ x: "100%" }}
            animate={{ x: 0 }}
            exit={{ x: "100%" }}
            transition={{ type: "spring", damping: 25 }}
            className="fixed inset-0 z-40 bg-gradient-to-br from-yellow-600 via-amber-500 to-orange-600 md:hidden"
          >
            <div className="flex flex-col items-center justify-center h-full space-y-10">
              {navItems.map((item, i) => (
                <motion.button
                  key={item.name}
                  initial={{ opacity: 0, x: 100 }}
                  animate={{ opacity: 1, x: 0 }}
                  transition={{ delay: i * 0.1 }}
                  onClick={() => scrollToSection(item.id)}
                  className="text-4xl font-bold text-white transition-all hover:text-yellow-200"
                  whileHover={{ scale: 1.1 }}
                  whileTap={{ scale: 0.95 }}
                >
                  {item.name}
                </motion.button>
              ))}
              <motion.div
                initial={{ opacity: 0 }}
                animate={{ opacity: 1 }}
                transition={{ delay: 0.6 }}
                className="mt-16 text-center"
              >
                <p className="mb-4 text-xl text-yellow-100">Ready to transform your brand?</p>
                <button
                  onClick={() => scrollToSection("contact")}
                  className="px-10 py-5 text-2xl font-bold text-yellow-600 bg-white rounded-full shadow-2xl"
                >
                  Get Quote Now
                </button>
              </motion.div>
            </div>
          </motion.div>
        )}
      </AnimatePresence>
    </>
  );
};

export default Navbar;
